    92→  var RAIOX_KEY = 'jakeos_raiox_2026';
    93→
    94→  function salvarRaioX() {
    95→    try {
    96→      localStorage.setItem(RAIOX_KEY, JSON.stringify(RAIOX));
    97→      flashRaioX('✓ Salvo');
    98→    } catch(e) {}
    99→  }
   100→
   101→  function carregarRaioX() {
   102→    try {
   103→      var salvo = localStorage.getItem(RAIOX_KEY);
   104→      if (salvo) return JSON.parse(salvo);
   105→    } catch(e) {}
   106→    return null;
   107→  }
   108→
   109→  function flashRaioX(msg) {
   110→    var el = document.getElementById('fin-raiox-status');
   111→    if (!el) return;
   112→    el.textContent = msg;
   113→    el.classList.add('fin-raiox-status-visible');
   114→    clearTimeout(el._timer);
   115→    el._timer = setTimeout(function() { el.classList.remove('fin-raiox-status-visible'); }, 2000);
   116→  }
   117→
   118→  var RAIOX = carregarRaioX() || JSON.parse(JSON.stringify(RAIOX_PADRAO));
   119→
   120→  var MESES_LABEL = ['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'];
   121→
   122→  // ── ESTADO ─────────────────────────────────────────────────────────────────
   123→  var mesSelecionado = new Date().getMonth() + 1;
   124→  var anoSelecionado = new Date().getFullYear();
   125→  var chartBarras    = null;
   126→  var chartDonut     = null;
   127→  var chartLinha     = null;
   128→  var chartMilhao    = null;
   129→  var metaMilhao     = 1000000;
   130→
   131→  // ── UTILITÁRIOS ────────────────────────────────────────────────────────────
   132→  function fmt(v) {
   133→    return 'R$ ' + Math.abs(v).toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
   134→  }
   135→  function fmtK(v) {
   136→    if (Math.abs(v) >= 1000000) return 'R$ ' + (v/1000000).toFixed(2).replace('.',',') + 'M';
   137→    if (Math.abs(v) >= 1000)    return 'R$ ' + (v/1000).toFixed(1).replace('.',',') + 'K';
   138→    return fmt(v);
   139→  }
   140→  function mesLabel(mes, ano) {
   141→    var n = ['','Janeiro','Fevereiro','Março','Abril','Maio','Junho','Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'];
   142→    return n[mes] + ' ' + ano;
   143→  }
   144→  function transacoesDo(mes, ano) {
   145→    var y = String(ano), m = String(mes).padStart(2,'0');
   146→    return TRANSACOES.filter(function(t){ return t.data.startsWith(y+'-'+m); });
   147→  }
   148→  function calcularKPIs(mes, ano) {
   149→    var lista    = transacoesDo(mes, ano);
   150→    var receita  = lista.filter(function(t){ return t.tipo==='Entrada'; }).reduce(function(s,t){ return s+t.valor; },0);
   151→    var despesas = lista.filter(function(t){ return t.tipo==='Saída';   }).reduce(function(s,t){ return s+t.valor; },0);
   152→    return { receita:receita, despesas:despesas, saldo:receita-despesas };
   153→  }
   154→
   155→  // ── RAIO-X: somatórios ─────────────────────────────────────────────────────
   156→  function raixoSomaLinha(itens, mes) {
   157→    return itens.reduce(function(s,item){ return s + (item.v[mes] || 0); }, 0);
   158→  }
   159→  function raixoTotaisMensais() {
   160→    var totais = { receitas:[], fixas:[], variaveis:[], saldo:[], acumulado:[] };
   161→    var acum = 0;
   162→    for (var m = 0; m < 12; m++) {
   163→      var r = raixoSomaLinha(RAIOX.entradas, m);
   164→      var f = raixoSomaLinha(RAIOX.fixas, m);
   165→      var v = raixoSomaLinha(RAIOX.variaveis, m);
   166→      var s = r - f - v;
   167→      acum += s;
   168→      totais.receitas.push(r);
   169→      totais.fixas.push(f);
   170→      totais.variaveis.push(v);
   171→      totais.saldo.push(s);
   172→      totais.acumulado.push(acum);
   173→    }
   174→    return totais;
   175→  }
   176→
   177→  // ── INICIALIZAÇÃO ──────────────────────────────────────────────────────────
   178→  function initFinanceiro() {
   179→    // Tabs internos
   180→    document.querySelectorAll('.fin-tab-btn').forEach(function(btn) {
   181→      btn.addEventListener('click', function() {
   182→        var tab = this.dataset.tab;
   183→        document.querySelectorAll('.fin-tab-btn').forEach(function(b){ b.classList.remove('active'); });
   184→        document.querySelectorAll('.fin-tab-pane').forEach(function(p){ p.classList.remove('active'); });
   185→        this.classList.add('active');
   186→        var pane = document.getElementById('fin-pane-' + tab);
   187→        if (pane) pane.classList.add('active');
   188→        if (tab === 'visao-geral')  { renderCharts(); renderRaioX(); }
   189→        if (tab === 'projecoes')    { renderGraficoLinha(); atualizarProjecoes(); }
   190→        if (tab === 'milhao')       { initProjetoMilhao(); }
   191→      });
   192→    });
   193→
   194→    // IA
   195→    var btnIA = document.getElementById('fin-ai-btn');
   196→    if (btnIA) btnIA.addEventListener('click', gerarAnaliseIA);
   197→
   198→    // Lançamentos
   199→    var btnAdd = document.getElementById('fin-add-btn');
   200→    if (btnAdd) btnAdd.addEventListener('click', adicionarLancamento);
   201→
   202→    var prevBtn = document.getElementById('fin-mes-prev');
   203→    var nextBtn = document.getElementById('fin-mes-next');
   204→    if (prevBtn) prevBtn.addEventListener('click', function(){ navegarMes(-1); });
   205→    if (nextBtn) nextBtn.addEventListener('click', function(){ navegarMes(1); });
   206→
   207→    var dataInput = document.getElementById('fin-data');
   208→    if (dataInput) dataInput.value = new Date().toISOString().split('T')[0];
   209→
   210→    // Filtro de mês na Visão Geral
   211→    var selectMes = document.getElementById('fin-visao-mes');
   212→    if (selectMes) {
   213→      selectMes.value = String(mesSelecionado);
   214→      selectMes.addEventListener('change', function () {
   215→        var novoMes = parseInt(this.value, 10) || mesSelecionado;
   216→        mesSelecionado = novoMes;
   217→        anoSelecionado = 2026;
   218→        atualizarTudo();
   219→        renderRaioX();
   220→        // Sincroniza label de lançamentos
   221→        atualizarMesLabel();
   222→      });
   223→    }
   224→
   225→    atualizarTudo();
   226→    renderRaioX();
   227→  }
   228→
   229→  function atualizarTudo() {
   230→    atualizarKPIs();
   231→    atualizarTabela();
   232→    atualizarProjecoes();
   233→    atualizarMesLabel();
   234→    renderCharts();
   235→  }
   236→
   237→  // ── KPIs — usa RAIOX como fonte principal ──────────────────────────────────
   238→  function calcularKPIsFromRaioX(mes, ano) {
   239→    if (ano !== 2026) return calcularKPIs(mes, ano);
   240→    var idx      = mes - 1;
   241→    var receita  = raixoSomaLinha(RAIOX.entradas,   idx);
   242→    var fixas    = raixoSomaLinha(RAIOX.fixas,       idx);
   243→    var variaveis = raixoSomaLinha(RAIOX.variaveis,  idx);
   244→    return { receita: receita, despesas: fixas + variaveis, saldo: receita - fixas - variaveis };
   245→  }
   246→
   247→  function atualizarKPIs() {
   248→    var kpis = calcularKPIsFromRaioX(mesSelecionado, anoSelecionado);
   249→    var acumulado = 0;
   250→    for (var m = 1; m <= mesSelecionado; m++) {
   251→      acumulado += calcularKPIsFromRaioX(m, anoSelecionado).saldo;
   252→    }
   253→    var elR = document.getElementById('fin-kpi-receita');
   254→    var elD = document.getElementById('fin-kpi-despesas');
   255→    var elS = document.getElementById('fin-kpi-saldo');
   256→    var elP = document.getElementById('fin-kpi-projecao');
   257→    var elM = document.getElementById('fin-kpi-receita-mes');
   258→    if (elR) elR.textContent = fmt(kpis.receita);
   259→    if (elD) elD.textContent = fmt(kpis.despesas);
   260→    if (elM) elM.textContent = mesLabel(mesSelecionado, anoSelecionado);
   261→    if (elS) {
   262→      elS.textContent = (kpis.saldo < 0 ? '-' : '') + fmt(kpis.saldo);
   263→      elS.className = 'fin-kpi-value ' + (kpis.saldo >= 0 ? 'fin-val-positive' : 'fin-val-negative');
   264→    }
   265→    if (elP) {
   266→      elP.textContent = (acumulado < 0 ? '-' : '') + fmt(acumulado);
   267→      elP.className = 'fin-kpi-value ' + (acumulado >= 0 ? 'fin-val-positive' : 'fin-val-negative');
   268→    }
   269→  }
   270→
   271→  // ── RAIO-X TABLE ───────────────────────────────────────────────────────────
   272→  function renderRaioX() {
   273→    var table = document.getElementById('fin-raiox-table');
   274→    if (!table) return;
   275→
   276→    var totais = raixoTotaisMensais();
   277→    var html = '';
   278→
   279→    // Cabeçalho
   280→    html += '<thead><tr><th class="fin-rx-th-label">Item</th>';
   281→    MESES_LABEL.forEach(function(m, i) {
   282→      var isPast = (i + 1) < mesSelecionado || (i + 1 === mesSelecionado);
   283→      html += '<th class="fin-rx-th-mes' + (isPast ? ' fin-rx-past' : ' fin-rx-future') + '">' + m + '</th>';
   284→    });
   285→    html += '<th class="fin-rx-th-anual">Total 2026</th></tr></thead>';
   286→
   287→    html += '<tbody>';
   288→
   289→    // ── ENTRADAS
   290→    html += '<tr class="fin-rx-section-header"><td colspan="14">↑ RECEITAS</td></tr>';
   291→    RAIOX.entradas.forEach(function(item, idx) {
   292→      html += renderRaioXLinha(item, 'entrada', 'entradas', idx);
   293→    });
   294→    html += renderRaioXAddLinha('entradas', 'entrada');
   295→    html += renderRaioXTotalLinha('TOTAL RECEITAS', totais.receitas, 'fin-rx-total fin-rx-total-entrada');
   296→
   297→    // ── DESPESAS FIXAS
   298→    html += '<tr class="fin-rx-section-header fin-rx-sec-saida"><td colspan="14">↓ DESPESAS FIXAS</td></tr>';
   299→    RAIOX.fixas.forEach(function(item, idx) {
   300→      html += renderRaioXLinha(item, 'fixa', 'fixas', idx);
   301→    });
   302→    html += renderRaioXAddLinha('fixas', 'fixa');
   303→    html += renderRaioXTotalLinha('TOTAL FIXAS', totais.fixas, 'fin-rx-total fin-rx-total-saida');
   304→
