   705→  // ── PROJEÇÕES (3 meses) ────────────────────────────────────────────────────
   706→  function atualizarProjecoes() {
   707→    var grid = document.getElementById('fin-proj-grid');
   708→    if (!grid) return;
   709→    var recorrentes = TRANSACOES.filter(function(t) {
   710→      var y = String(anoSelecionado), m = String(mesSelecionado).padStart(2,'0');
   711→      return t.data.startsWith(y+'-'+m) && t.recorrente;
   712→    });
   713→    var meses = [];
   714→    for (var i = 1; i <= 3; i++) {
   715→      var mesProj = mesSelecionado + i, anoProj = anoSelecionado;
   716→      if (mesProj > 12) { mesProj -= 12; anoProj++; }
   717→      var entrada = recorrentes.filter(function(t){ return t.tipo==='Entrada'; }).reduce(function(s,t){ return s+t.valor; },0);
   718→      var saida   = recorrentes.filter(function(t){ return t.tipo==='Saída';   }).reduce(function(s,t){ return s+t.valor; },0);
   719→      meses.push({ mes:mesProj, ano:anoProj, entrada:entrada, saida:saida, saldo:entrada-saida });
   720→    }
   721→    grid.innerHTML = meses.map(function(m) {
   722→      var cls   = m.saldo >= 0 ? 'fin-proj-positive' : 'fin-proj-negative';
   723→      var sinal = m.saldo >= 0 ? '+' : '-';
   724→      return '<div class="fin-proj-card">' +
   725→        '<div class="fin-proj-mes">' + mesLabel(m.mes, m.ano) + '</div>' +
   726→        '<div class="fin-proj-row"><span>Ganhos Fixos</span><span class="fin-val-positive">' + fmt(m.entrada) + '</span></div>' +
