   734→  // ── PROJETO 1 MILHÃO ──────────────────────────────────────────────────────
   735→  var _milhaoInited = false;
   736→  function initProjetoMilhao() {
   737→    if (_milhaoInited) return;
   738→    _milhaoInited = true;
   739→
   740→    // Sugerir aporte = média do saldo mensal (positivo) dos dados disponíveis
   741→    var totais = raixoTotaisMensais();
   742→    var saldosPos = totais.saldo.filter(function(s){ return s > 0; });
   743→    var mediaSaldo = saldosPos.length > 0
   744→      ? Math.round(saldosPos.reduce(function(s,v){ return s+v; },0) / saldosPos.length)
   745→      : 2000;
   746→    var elAporte = document.getElementById('mil-aporte');
   747→    if (elAporte) elAporte.value = mediaSaldo;
   748→
   749→    // Presets de taxa
   750→    document.querySelectorAll('.fin-preset-btn').forEach(function(btn) {
   751→      btn.addEventListener('click', function() {
   752→        document.querySelectorAll('.fin-preset-btn').forEach(function(b){ b.classList.remove('active'); });
   753→        this.classList.add('active');
   754→        var el = document.getElementById('mil-taxa');
   755→        if (el) el.value = this.dataset.taxa;
   756→        calcularMilhao();
   757→      });
   758→    });
   759→
   760→    // Presets de meta
   761→    document.querySelectorAll('.fin-meta-btn').forEach(function(btn) {
   762→      btn.addEventListener('click', function() {
   763→        document.querySelectorAll('.fin-meta-btn').forEach(function(b){ b.classList.remove('active'); });
   764→        this.classList.add('active');
   765→        metaMilhao = parseInt(this.dataset.meta);
   766→        var badge = document.getElementById('mil-meta-badge');
   767→        if (badge) badge.textContent = 'Meta: ' + fmt(metaMilhao);
   768→        calcularMilhao();
   769→      });
   770→    });
   771→
   772→    // Botão calcular
   773→    var btnCalc = document.getElementById('mil-calc-btn');
   774→    if (btnCalc) btnCalc.addEventListener('click', calcularMilhao);
   775→
   776→    // Recalcular em tempo real ao mudar inputs
   777→    ['mil-aporte','mil-patrimonio','mil-taxa'].forEach(function(id) {
   778→      var el = document.getElementById(id);
   779→      if (el) el.addEventListener('input', calcularMilhao);
   780→    });
   781→
   782→    // Calcular logo de cara
   783→    calcularMilhao();
   784→  }
   785→
   786→  function calcularMilhao() {
   787→    var aporte     = parseFloat(document.getElementById('mil-aporte')    ?.value) || 0;
   788→    var patrimonio = parseFloat(document.getElementById('mil-patrimonio') ?.value) || 0;
   789→    var taxa       = (parseFloat(document.getElementById('mil-taxa')      ?.value) || 1) / 100;
   790→    var meta       = metaMilhao;
   791→
   792→    // Data de nascimento: 05/04/2001
   793→    var nascimento = new Date(2001, 3, 5); // April 5, 2001
   794→
   795→    if (aporte <= 0 && patrimonio < meta) {
   796→      return;
   797→    }
   798→
   799→    // Cálculo iterativo: FV = PV*(1+r)^n + PMT*((1+r)^n - 1)/r
   800→    var n = 0, fv = patrimonio;
   801→    var MAX = 12000; // 1000 anos max
   802→    while (fv < meta && n < MAX) {
   803→      fv = fv * (1 + taxa) + aporte;
   804→      n++;
   805→    }
   806→
   807→    if (n >= MAX) {
   808→      // Nunca vai atingir
   809→      var elData  = document.getElementById('mil-data');
   810→      var elIdade = document.getElementById('mil-idade');
   811→      if (elData)  elData.textContent  = 'Nunca com este aporte';
   812→      if (elIdade) elIdade.textContent = 'Aumente o aporte mensal';
   813→      return;
   814→    }
   815→
   816→    // Data alvo
   817→    var hoje       = new Date();
   818→    var dataAlvo   = new Date(hoje);
   819→    dataAlvo.setMonth(dataAlvo.getMonth() + n);
   820→
   821→    // Idade na data alvo
   822→    var diffMs    = dataAlvo - nascimento;
   823→    var idadeTotal = diffMs / (1000 * 60 * 60 * 24 * 365.25);
   824→    var anos      = Math.floor(idadeTotal);
   825→    var mesesR    = Math.floor((idadeTotal - anos) * 12);
   826→
   827→    // Total aportado vs juros
   828→    var totalAportado = aporte * n + patrimonio;
   829→    var jurosGerados  = fv - totalAportado;
   830→
   831→    // Progresso atual
   832→    var pct = Math.min((patrimonio / meta) * 100, 100);
   833→
   834→    // Mostrar display
   835→    var idle    = document.getElementById('mil-idle');
   836→    var display = document.getElementById('mil-display');
   837→    if (idle)    idle.classList.add('hidden');
   838→    if (display) display.classList.remove('hidden');
   839→
   840→    // Preencher valores
   841→    var elData  = document.getElementById('mil-data');
   842→    var elIdade = document.getElementById('mil-idade');
   843→    var elMeses = document.getElementById('mil-meses');
   844→    var elTotalA= document.getElementById('mil-total-aportado');
   845→    var elJuros = document.getElementById('mil-juros');
   846→    var elFill  = document.getElementById('mil-prog-fill');
   847→    var elGlow  = document.getElementById('mil-prog-glow');
   848→    var elPct   = document.getElementById('mil-prog-pct');
   849→    var elAtual = document.getElementById('mil-prog-atual');
   850→    var elMeta  = document.getElementById('mil-prog-meta');
   851→    var badge   = document.getElementById('mil-meta-badge');
   852→
   853→    var meses_str = ['Jan','Fev','Mar','Abr','Mai','Jun','Jul','Ago','Set','Out','Nov','Dez'];
   854→    var dataStr = ('0' + dataAlvo.getDate()).slice(-2) + '/' + meses_str[dataAlvo.getMonth()] + '/' + dataAlvo.getFullYear();
   855→
   856→    if (badge)   badge.textContent = 'Meta: ' + fmt(meta);
   857→    if (elData)  elData.textContent  = dataStr;
   858→    if (elIdade) elIdade.textContent = anos + ' anos e ' + mesesR + ' meses';
   859→    if (elMeses) elMeses.textContent = n + ' meses (' + Math.floor(n/12) + ' anos)';
   860→    if (elTotalA) elTotalA.textContent = fmt(totalAportado);
   861→    if (elJuros)  elJuros.textContent  = fmt(jurosGerados);
   862→    if (elFill)   elFill.style.width   = pct + '%';
   863→    if (elGlow)   elGlow.style.left    = pct + '%';
   864→    if (elPct)    elPct.textContent    = pct.toFixed(1) + '% concluído';
   865→    if (elAtual)  elAtual.textContent  = fmt(patrimonio);
   866→    if (elMeta)   elMeta.textContent   = fmt(meta);
   867→
   868→    // Mini gráfico de evolução
   869→    renderMilhaoChart(n, aporte, patrimonio, taxa, meta);
   870→  }
   871→
   872→  function renderMilhaoChart(n, aporte, patrimonio, taxa, meta) {
   873→    var canvas = document.getElementById('mil-chart-evolucao');
   874→    if (!canvas || typeof Chart === 'undefined') return;
   875→
   876→    // Gerar pontos a cada 12 meses
   877→    var pontos = [], labels = [];
   878→    var fv = patrimonio;
   879→    var step = Math.max(1, Math.floor(n / 30)); // max 30 pontos
   880→    for (var i = 0; i <= n; i++) {
   881→      if (i % step === 0 || i === n) {
   882→        labels.push('Mês ' + i);
   883→        pontos.push(parseFloat(fv.toFixed(2)));
   884→      }
   885→      fv = fv * (1 + taxa) + aporte;
   886→    }
   887→
   888→    if (chartMilhao) chartMilhao.destroy();
   889→    chartMilhao = new Chart(canvas, {
   890→      type: 'line',
   891→      data: {
   892→        labels: labels,
   893→        datasets: [{
