   897→          backgroundColor: 'rgba(0,229,255,0.08)',
   898→          borderWidth: 2,
   899→          pointRadius: 0,
   900→          tension: 0.4,
   901→          fill: true,
   902→        },{
   903→          label: 'Meta',
   904→          data: Array(labels.length).fill(meta),
   905→          borderColor: 'rgba(105,240,174,0.5)',
   906→          borderWidth: 1,
   907→          borderDash: [6,4],
   908→          pointRadius: 0,
   909→          fill: false,
   910→        }]
   911→      },
   912→      options: {
   913→        responsive: true, maintainAspectRatio: false,
   914→        plugins: {
   915→          legend: { labels: { color: '#b0bec5', font: { family: 'Rajdhani', size: 11 }, boxWidth: 12 } },
   916→          tooltip: { callbacks: { label: function(ctx){ return ' R$ '+ctx.raw.toLocaleString('pt-BR',{minimumFractionDigits:2}); } } }
   917→        },
   918→        scales: {
   919→          x: { display: false },
   920→          y: {
   921→            ticks: { color: '#b0bec5', font: { family: 'Rajdhani', size: 11 }, callback: function(v){ return 'R$ '+(v/1000).toFixed(0)+'K'; } },
   922→            grid: { color: 'rgba(0,229,255,0.06)' }
   923→          }
   924→        }
   925→      }
   926→    });
   927→  }
   928→
   929→  // ── ANÁLISE IA ─────────────────────────────────────────────────────────────
   930→  function gerarAnaliseIA() {
   931→    var result  = document.getElementById('fin-ai-result');
   932→    var loading = document.getElementById('fin-ai-loading');
   933→    var text    = document.getElementById('fin-ai-text');
   934→    if (!result || !loading || !text) return;
   935→    result.classList.remove('hidden');
   936→    loading.classList.remove('hidden');
   937→    text.classList.add('hidden');
   938→
   939→    var kpis    = calcularKPIs(mesSelecionado, anoSelecionado);
   940→    var kpisAnt = mesSelecionado > 1 ? calcularKPIs(mesSelecionado-1, anoSelecionado) : {receita:0,despesas:0,saldo:0};
   941→    var payload = { mes: mesLabel(mesSelecionado, anoSelecionado), receita: kpis.receita, despesas: kpis.despesas, saldo: kpis.saldo, receita_ant: kpisAnt.receita, desp_ant: kpisAnt.despesas };
   942→
   943→    fetch('/api/financeiro/analise', { method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify(payload) })
   944→    .then(function(r){ return r.json(); })
   945→    .then(function(data) {
   946→      loading.classList.add('hidden');
   947→      text.classList.remove('hidden');
   948→      text.innerHTML = '<span class="fin-ai-jake">🤖 Jake diz:</span><br>' + (data.analise || 'Análise indisponível.');
   949→    })
   950→    .catch(function() {
   951→      loading.classList.add('hidden');
   952→      text.classList.remove('hidden');
   953→      var difR = kpis.receita - kpisAnt.receita, difD = kpis.despesas - kpisAnt.despesas;
   954→      text.innerHTML = '<span class="fin-ai-jake">🤖 Jake diz:</span><br>' + gerarAnaliseLocal(kpis, kpisAnt, difR, difD);
   955→    });
   956→  }
   957→
   958→  function gerarAnaliseLocal(kpis, kpisAnt, difR, difD) {
   959→    var partes = [];
   960→    if (kpisAnt.receita > 0) {
   961→      var varR = ((difR / kpisAnt.receita) * 100).toFixed(1);
   962→      partes.push(difR > 0
   963→        ? 'Suas receitas cresceram <strong>' + varR + '%</strong> em relação ao mês anterior — ótima evolução!'
   964→        : difR < 0 ? 'Suas receitas recuaram <strong>' + Math.abs(varR) + '%</strong> vs. mês anterior. Reveja a entrada de novos projetos.'
   965→        : 'Suas receitas se mantiveram estáveis.');
   966→    }
   967→    var tx = ((kpis.despesas / kpis.receita) * 100).toFixed(1);
   968→    partes.push('Você comprometeu <strong>' + tx + '%</strong> da receita com despesas este mês.');
   969→    partes.push(kpis.saldo >= 0
   970→      ? 'Saldo positivo de <strong>' + fmt(kpis.saldo) + '</strong> — considere destinar parte para investimentos e reserva de emergência.'
   971→      : 'Saldo negativo de <strong>' + fmt(Math.abs(kpis.saldo)) + '</strong> — revise despesas variáveis e parcelamentos.');
   972→    return partes.join(' ');
   973→  }
